function setMidPos(HNDZ, MainFrame)
	MainFrame.Position = UDim2.new(0, (HNDZ.AbsoluteSize.X // 2 - MainFrame.Size.X.Offset // 2), 0, (HNDZ.AbsoluteSize.Y // 2 - MainFrame.Size.Y.Offset // 2))
	return MainFrame.Position
end
